class Solution {
public:
    int maxSubstrings(string word) {
        int count = 0;
        for (int i = 0; i < word.size() - 3; ++i) {
            for (int j = i + 4; j <= word.size(); ++j) {
                if (word[i] == word[j - 1] && word[i] == word[j]) {
                    count++;
                    i = j - 1;
                    break;
                }
            }
        }
        return count;
    }
};
